module top_module(clk, rst, obf_IRWr, im_dout, instr);input         clk;
   input         rst;
   input         obf_IRWr; 
   input  [31:0] im_dout;
   output [31:0] instr;

   reg [31:0] instr;

   always @(posedge clk or posedge rst) begin
      if ( rst ) 
         instr <= 0;
      else if (obf_IRWr)
         instr <= im_dout;
   end 

endmodule
